            throw new IllegalArgumentException("Invalid sort field: " + orderBy);
        }

        // Validate sort direction against whitelist
        if (!ALLOWED_SORT_DIRECTIONS.contains(normalizedSortDirection)) {
            throw new IllegalArgumentException("Invalid sort direction: " + sortDirection);
        }

        // Call mapper with validated parameters
        return userMapper.getUsersByOrder(normalizedOrderBy, normalizedSortDirection);
    }

    /**
     * Get all users
     * @return User list
     */
    public List<User> getAllUsers() {
        return userMapper.getAllUsers();
    }
}
